	@Test
	void initWrapsIoFailuresInServletException() throws Exception {
		Path tempDir = Files.createTempDirectory("abstract-servlet-init");
		Files.createDirectories(
				tempDir.resolve(PlatformFactory.getPlatform().getRelativeApplicationDataDir("Workbench"))
						.resolve("conf")
						.resolve("application.properties"));
		String previous = System.getProperty(Platform.APPDATA_BASEDIR_PROPERTY);
		System.setProperty(Platform.APPDATA_BASEDIR_PROPERTY, tempDir.toString());

		try {
			ExposedAbstractServlet servlet = new ExposedAbstractServlet();
			TestServletConfig config = new TestServletConfig("example", new MockServletContext(), java.util.Map.of());

			assertThatThrownBy(() -> servlet.init(config))
					.isInstanceOf(ServletException.class)
					.hasCauseInstanceOf(IOException.class);
		} finally {
			if (previous == null) {
				System.clearProperty(Platform.APPDATA_BASEDIR_PROPERTY);
			} else {
				System.setProperty(Platform.APPDATA_BASEDIR_PROPERTY, previous);
			}
		}
	}

