	@Test
	void checkJsonpUsesConfiguredCallbackNamesAndRejectsInvalidValues() throws Exception {
		ExposedAbstractServlet servlet = new ExposedAbstractServlet();
		servlet.init(new TestServletConfig("example", new MockServletContext(), java.util.Map.of()));
		servlet.appConfig.getProperties().setProperty(AbstractServlet.JSONP_ENABLED, "true");

		MockHttpServletRequest defaultRequest = new MockHttpServletRequest();
		defaultRequest.setParameter(AbstractServlet.DEFAULT_JSONP_CALLBACK_PARAMETER, " ");
		QueryResultWriter defaultWriter = servlet.exposeCheckJSONP(defaultRequest, new ByteArrayOutputStream());
		assertThat(defaultWriter).isNotNull();
		assertThat(defaultWriter.getWriterConfig().get(BasicQueryWriterSettings.JSONP_CALLBACK))
				.isEqualTo(BasicQueryWriterSettings.JSONP_CALLBACK.getDefaultValue());

		servlet.appConfig.getProperties().setProperty(AbstractServlet.JSONP_CALLBACK_PARAMETER, "jsonp");
		MockHttpServletRequest customRequest = new MockHttpServletRequest();
		customRequest.setParameter("jsonp", "handleResult");
		QueryResultWriter customWriter = servlet.exposeCheckJSONP(customRequest, new ByteArrayOutputStream());
		assertThat(customWriter.getWriterConfig().get(BasicQueryWriterSettings.JSONP_CALLBACK))
				.isEqualTo("handleResult");

		MockHttpServletRequest invalidRequest = new MockHttpServletRequest();
		invalidRequest.setParameter("jsonp", "123bad");
		assertThatThrownBy(() -> servlet.exposeCheckJSONP(invalidRequest, new ByteArrayOutputStream()))
				.isInstanceOf(IOException.class)
				.hasMessage("Callback function name was invalid");
	}

