	private static final class ExposedAbstractServlet extends AbstractServlet {
		private boolean httpServiceCalled;
		private QueryResultWriter resultWriter;

		@Override
		public void service(HttpServletRequest req, HttpServletResponse resp) throws ServletException, IOException {
			httpServiceCalled = true;
		}

		@Override
		protected QueryResultWriter getResultWriter(HttpServletRequest req, ServletResponse resp,
				OutputStream outputStream) throws IOException {
			if (resultWriter != null) {
				return resultWriter;
			}
			return super.getResultWriter(req, resp, outputStream);
		}

		private void invokeDefaultService(HttpServletRequest req, HttpServletResponse resp)
				throws ServletException, IOException {
			super.service(req, resp);
		}

		private org.eclipse.rdf4j.workbench.util.TupleResultBuilder exposeGetTupleResultBuilder(HttpServletRequest req,
				HttpServletResponse resp, ByteArrayOutputStream outputStream) throws Exception {
			return getTupleResultBuilder(req, resp, outputStream);
		}

		private QueryResultFormat exposeGetBooleanResultFormat(HttpServletRequest req) {
			return getBooleanResultFormat(req, mock(ServletResponse.class));
		}

		private QueryResultFormat exposeGetTupleResultFormat(HttpServletRequest req) {
			return getTupleResultFormat(req, mock(ServletResponse.class));
		}

		private QueryResultFormat exposeGetJSONPResultFormat(HttpServletRequest req) {
			return getJSONPResultFormat(req, mock(ServletResponse.class));
		}

		private QueryResultWriter exposeCheckJSONP(HttpServletRequest req, ByteArrayOutputStream outputStream)
				throws Exception {
			return checkJSONP(req, outputStream);
		}
	}

